  "pr.starterFeat1": {"en":"Full unit detail in <strong>1 market</strong> — size, floor, desks, rent, fit-out","fr":"Détail complet des unités sur <strong>1 marché</strong> — surface, étage, postes, loyer, aménagement","de":"Vollständige Flächendetails in <strong>1 Markt</strong> — Größe, Etage, Arbeitsplätze, Miete, Ausbau","es":"Detalle completo de unidades en <strong>1 mercado</strong> — superficie, planta, puestos, renta, acondicionamiento","it":"Dettaglio completo delle unità in <strong>1 mercato</strong> — superficie, piano, postazioni, affitto, allestimento","nl":"Volledige unitdetails in <strong>1 markt</strong> — oppervlakte, verdieping, werkplekken, huur, inrichting"},
