  "pr.membershipFeat1": {"en":"Full unit detail across <strong>all active markets</strong>","fr":"Détail complet des unités sur <strong>tous les marchés actifs</strong>","de":"Vollständige Flächendetails in <strong>allen aktiven Märkten</strong>","es":"Detalle completo de unidades en <strong>todos los mercados activos</strong>","it":"Dettaglio completo delle unità in <strong>tutti i mercati attivi</strong>","nl":"Volledige unitdetails in <strong>alle actieve markten</strong>"},
