  "pr.membershipFeat6": {"en":"Managed Market Scans — coming soon","fr":"Market Scans gérés — bientôt disponible","de":"Verwaltete Market Scans — demnächst verfügbar","es":"Market Scans gestionados — próximamente","it":"Market Scan gestiti — prossimamente","nl":"Beheerde Market Scans — binnenkort beschikbaar"},
  "pr.ctaRequestMembership": {"en":"Request Membership access","fr":"Demander l'accès Membership","de":"Membership-Zugang anfordern","es":"Solicitar acceso Membership","it":"Richiedi l'accesso Membership","nl":"Membership-toegang aanvragen"},
