  "auth.signinIntro": {"en":"Sign in to your URBN account","fr":"Connectez-vous à votre compte URBN","de":"Melden Sie sich bei Ihrem URBN-Konto an","es":"Inicia sesión en tu cuenta de URBN","it":"Accedi al tuo account URBN","nl":"Log in op uw URBN-account"},
