  "auth.noAccount": {"en":"No account? <a href=\"/sign-up\" style=\"color:var(--navy);\">Create one</a>","fr":"Pas de compte ? <a href=\"/sign-up\" style=\"color:var(--navy);\">Créez-en un</a>","de":"Kein Konto? <a href=\"/sign-up\" style=\"color:var(--navy);\">Erstellen Sie eines</a>","es":"¿Sin cuenta? <a href=\"/sign-up\" style=\"color:var(--navy);\">Crea una</a>","it":"Nessun account? <a href=\"/sign-up\" style=\"color:var(--navy);\">Creane uno</a>","nl":"Geen account? <a href=\"/sign-up\" style=\"color:var(--navy);\">Maak er een aan</a>"},
  "auth.signinHelper": {"en":"Access to building details, pricing, and introductions requires a verified corporate account.","fr":"L'accès aux détails des immeubles, aux tarifs et aux mises en relation nécessite un compte professionnel vérifié.","de":"Der Zugang zu Gebäudedetails, Preisen und Vermittlungen erfordert ein verifiziertes Unternehmenskonto.","es":"El acceso a los detalles de los edificios, los precios y las presentaciones requiere una cuenta corporativa verificada.","it":"L'accesso ai dettagli degli edifici, ai prezzi e alle presentazioni richiede un account aziendale verificato.","nl":"Toegang tot gebouwdetails, prijzen en introducties vereist een geverifieerd zakelijk account."},
  "auth.createAccount": {"en":"Create Account","fr":"Créer un compte","de":"Konto erstellen","es":"Crear cuenta","it":"Crea account","nl":"Account aanmaken"},
  "auth.signupH1": {"en":"Join URBN","fr":"Rejoignez URBN","de":"URBN beitreten","es":"Únete a URBN","it":"Unisciti a URBN","nl":"Word lid van URBN"},
  "auth.signupIntro": {"en":"Corporate accounts only. A verified corporate email is required — free webmail (Gmail, Outlook, Yahoo, etc.) is not accepted. Paid tiers are activated after manual review.","fr":"Comptes professionnels uniquement. Une adresse e-mail professionnelle vérifiée est requise — les messageries gratuites (Gmail, Outlook, Yahoo, etc.) ne sont pas acceptées. Les formules payantes sont activées après examen manuel.","de":"Nur Unternehmenskonten. Eine verifizierte geschäftliche E-Mail-Adresse ist erforderlich — kostenlose Webmail-Dienste (Gmail, Outlook, Yahoo usw.) werden nicht akzeptiert. Kostenpflichtige Stufen werden nach manueller Prüfung aktiviert.","es":"Solo cuentas corporativas. Se requiere un correo corporativo verificado — no se aceptan correos gratuitos (Gmail, Outlook, Yahoo, etc.). Los planes de pago se activan tras una revisión manual.","it":"Solo account aziendali. È richiesta un'e-mail aziendale verificata — le webmail gratuite (Gmail, Outlook, Yahoo, ecc.) non sono accettate. I piani a pagamento vengono attivati dopo una verifica manuale.","nl":"Alleen zakelijke accounts. Een geverifieerd zakelijk e-mailadres is vereist — gratis webmail (Gmail, Outlook, Yahoo, enz.) wordt niet geaccepteerd. Betaalde niveaus worden geactiveerd na handmatige beoordeling."},
