  "auth.errCorpEmail": {"en":"Enter a valid corporate email (free webmail not accepted).","fr":"Saisissez une adresse e-mail professionnelle valide (messageries gratuites non acceptées).","de":"Geben Sie eine gültige geschäftliche E-Mail-Adresse ein (kostenlose Webmail nicht akzeptiert).","es":"Introduce un correo corporativo válido (no se aceptan correos gratuitos).","it":"Inserisci un'e-mail aziendale valida (webmail gratuite non accettate).","nl":"Voer een geldig zakelijk e-mailadres in (gratis webmail niet geaccepteerd)."},
