  "lb.unitFacilitiesHint": {"en":"Facilities specific to this space — these are separate from the building amenities.","fr":"Équipements propres à cet espace — distincts des équipements de l'immeuble.","de":"Einrichtungen speziell für diese Fläche — getrennt von den Gebäudeausstattungen.","es":"Instalaciones específicas de este espacio, separadas de las del edificio.","it":"Servizi specifici di questo spazio, separati da quelli dell'edificio.","nl":"Voorzieningen specifiek voor deze ruimte — los van de gebouwvoorzieningen."},
  "lb.bathroomsCount": {"en":"Number of bathrooms","fr":"Nombre de salles d'eau","de":"Anzahl der Toiletten","es":"Número de baños","it":"Numero di bagni","nl":"Aantal toiletten"},
