  "lb.errSvc": {"en":"Service charge must be numeric.","fr":"Les charges doivent être numériques.","de":"Die Nebenkosten müssen numerisch sein.","es":"Los gastos de servicio deben ser numéricos.","it":"Le spese di servizio devono essere numeriche.","nl":"Servicekosten moeten numeriek zijn."},
